(()=>{"use strict";const t="http://localhost:8000";chrome.runtime.onInstalled.addListener(()=>{console.log("BuyWise extension installed")}),chrome.runtime.onMessage.addListener((e,n,r)=>{if("BUYWISE_FETCH"===(null==e?void 0:e.type)){const{asin:n}=e;return Promise.all([fetch(`${t}/predict/${n}`).then(async t=>{if(!t.ok)throw new Error(`predict: ${t.status}`);return t.json()}),fetch(`${t}/price-history/${n}`).then(async t=>{if(!t.ok)throw new Error(`price-history: ${t.status}`);return t.json()})]).then(([t,e])=>r({ok:!0,predict:t,history:e})).catch(t=>r({ok:!1,error:t.message})),!0}return"BUYWISE_POST_ACTIVITY"===(null==e?void 0:e.type)&&(fetch(`${t}/activity`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({asin:e.asin,action:e.action,timestamp:(new Date).toISOString()})}).catch(()=>{}),!1)})})();